#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n;
    scanf("%d", &n);

    double *arr = (double *)malloc(n * sizeof(double));
    if (arr == NULL) {
        return 1;
    }

    for (int i = 0; i < n; i++) {
        scanf("%lf", arr + i);
    }

    double *left = arr;
    double *right = arr + n - 1;

    while (left < right) {
        double temp = *left;
        *left = *right;
        *right = temp;
        left++;
        right--;
    }

    for (int i = 0; i < n; i++) {
        printf("%.1f\n", *(arr + i));
    }

    free(arr);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n;
    scanf("%d", &n);

    int *arr = (int *)malloc(n * sizeof(int));
    if (arr == NULL) {
        return 1;
    }

    for (int i = 0; i < n; i++) {
        scanf("%d", arr + i);
    }

    int sum = 0;
    int *ptr = arr;

    for (int i = 0; i < n; i++) {
        sum += *ptr;
        ptr++;
    }

    printf("%d\n", sum);

    free(arr);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main(void) {
    char original[201];
    fgets(original, sizeof(original), stdin);

    int len = strlen(original);
    char *copy = (char *)malloc((len + 1) * sizeof(char));
    if (copy == NULL) {
        return 1;
    }

    char *src = original;
    char *dst = copy;

    while (*src != '\0') {
        *dst = *src;
        src++;
        dst++;
    }
    *dst = '\0';

    printf("%s", original);
    printf("%s", copy);

    free(copy);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int m, n;
    scanf("%d %d", &m, &n);

    int **array = (int **)malloc(m * sizeof(int *));
    if (array == NULL) {
        return 1;
    }

    for (int i = 0; i < m; i++) {
        array[i] = (int *)malloc(n * sizeof(int));
        if (array[i] == NULL) {
            return 1;
        }
    }

    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            scanf("%d", &array[i][j]);
        }
    }

    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            printf("%d", array[i][j]);
            if (j < n - 1) {
                printf(" ");
            }
        }
        printf("\n");
    }

    for (int i = 0; i < m; i++) {
        free(array[i]);
    }
    free(array);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n;
    scanf("%d", &n);

    double *arr = (double *)malloc(n * sizeof(double));
    if (arr == NULL) {
        return 1;
    }

    for (int i = 0; i < n; i++) {
        scanf("%lf", arr + i);
    }

    double *maxPtr = arr;
    int maxIndex = 0;

    for (int i = 1; i < n; i++) {
        if (*(arr + i) > *maxPtr) {
            maxPtr = arr + i;
            maxIndex = i;
        }
    }

    printf("%.1f at position %d\n", *maxPtr, maxIndex);

    free(arr);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int capacity = 10;
    int count = 0;
    int *arr = (int *)malloc(capacity * sizeof(int));
    if (arr == NULL) {
        return 1;
    }

    int num;
    while (scanf("%d", &num) == 1) {
        if (count == capacity) {
            capacity *= 2;
            int *temp = (int *)realloc(arr, capacity * sizeof(int));
            if (temp == NULL) {
                free(arr);
                return 1;
            }
            arr = temp;
        }
        arr[count] = num;
        count++;
    }

    for (int i = 0; i < count; i++) {
        printf("%d\n", arr[i]);
    }
    printf("Count: %d, Capacity: %d\n", count, capacity);

    free(arr);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main(void) {
    char buffer1[201], buffer2[201];
    fgets(buffer1, sizeof(buffer1), stdin);
    fgets(buffer2, sizeof(buffer2), stdin);

    int len1 = strlen(buffer1);
    int len2 = strlen(buffer2);

    char *str1 = (char *)malloc((len1 + 1) * sizeof(char));
    char *str2 = (char *)malloc((len2 + 1) * sizeof(char));
    if (str1 == NULL || str2 == NULL) {
        return 1;
    }

    strcpy(str1, buffer1);
    strcpy(str2, buffer2);

    char *ptr1 = str1;
    char *ptr2 = str2;
    int position = 0;
    int equal = 1;

    while (*ptr1 != '\0' && *ptr2 != '\0') {
        if (*ptr1 != *ptr2) {
            equal = 0;
            break;
        }
        ptr1++;
        ptr2++;
        position++;
    }

    if (*ptr1 != *ptr2) {
        equal = 0;
    }

    if (equal) {
        printf("Equal\n");
        printf("%d\n", -1);
    } else {
        printf("Not equal\n");
        printf("%d\n", position);
    }

    free(str1);
    free(str2);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int m;
    scanf("%d", &m);

    int **rows = (int **)malloc(m * sizeof(int *));
    int *sizes = (int *)malloc(m * sizeof(int));
    if (rows == NULL || sizes == NULL) {
        return 1;
    }

    for (int i = 0; i < m; i++) {
        scanf("%d", &sizes[i]);
        rows[i] = (int *)malloc(sizes[i] * sizeof(int));
        if (rows[i] == NULL) {
            return 1;
        }

        for (int j = 0; j < sizes[i]; j++) {
            scanf("%d", &rows[i][j]);
        }
    }

    for (int i = 0; i < m; i++) {
        int sum = 0;
        for (int j = 0; j < sizes[i]; j++) {
            sum += rows[i][j];
        }
        printf("%d\n", sum);
    }

    for (int i = 0; i < m; i++) {
        free(rows[i]);
    }
    free(rows);
    free(sizes);

    return 0;
}

#include <stdio.h>
#include <stdlib.h>

void swap(int **a, int **b) {
    int temp = **a;
    **a = **b;
    **b = temp;
}

int main(void) {
    int n;
    scanf("%d", &n);

    int *arr = (int *)malloc(n * sizeof(int));
    if (arr == NULL) {
        return 1;
    }

    for (int i = 0; i < n; i++) {
        scanf("%d", &arr[i]);
    }

    int i, j;
    scanf("%d %d", &i, &j);

    swap(&arr[i], &arr[j]);

    for (int k = 0; k < n; k++) {
        printf("%d", arr[k]);
        if (k < n - 1) {
            printf(" ");
        }
    }
    printf("\n");

    free(arr);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int value;
    struct Node *next;
} Node;

int main(void) {
    int n;
    scanf("%d", &n);

    Node *head = NULL;
    Node *current = NULL;

    for (int i = 0; i < n; i++) {
        int val;
        scanf("%d", &val);

        Node *newNode = (Node *)malloc(sizeof(Node));
        if (newNode == NULL) {
            return 1;
        }

        newNode->value = val;
        newNode->next = NULL;

        if (head == NULL) {
            head = newNode;
            current = newNode;
        } else {
            current->next = newNode;
            current = newNode;
        }
    }

    Node *ptr = head;
    while (ptr != NULL) {
        printf("%d\n", ptr->value);
        ptr = ptr->next;
    }

    ptr = head;
    while (ptr != NULL) {
        Node *temp = ptr;
        ptr = ptr->next;
        free(temp);
    }

    return 0;
}
